sevColor:
function sevColor(sev) {
  return { high: C.red, med: C.orange, low: C.textDim }[sev] || C.textDim;
}

sevBg:
function sevBg(sev) {
  return { high: C.redDim, med: C.orangeDim, low: '#1e1e1e' }[sev] || '#1e1e1e';
}

sevDot:
function sevDot(sev) {
  return (
    <span style={{ display:'inline-block', width:6, height:6, borderRadius:'50%',
      background: sevColor(sev), flexShrink:0 }} />
  );
}

Ico:
function Ico({ d, size=13, col='currentColor' }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none"
      stroke={col} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"
      style={{ display:'block', flexShrink:0 }}>
      <path d={d} />
    </svg>
  );
}

Tag:
function Tag({ sev, children, small }) {
  return (
    <span style={{
      display:'inline-flex', alignItems:'center', gap:3,
      padding: small ? '0px 5px' : '1px 6px',
      fontSize: small ? 10 : 10.5,
      fontFamily: C.mono,
      fontWeight:500,
      color: sevColor(sev),
      background: sevBg(sev),
      border: `1px solid ${sev==='high' ? '#4a2020' : sev==='med' ? '#3d2a10' : '#282828'}`,
      borderRadius: 3,
      letterSpacing: '0.02em',
      whiteSpace:'nowrap',
    }}>
      {children}
    </span>
  );
}

