// ─── analyzing state ───────────────────────────────────────────────────────────
function AnalyzingState({ lang='js', lt }) {
  const lth = lt || getLangTheme(lang);
  const [activePhase, setActivePhase] = useState(2);
  const [scrubber, setScrubber] = useState(1);
  const [logOpen, setLogOpen] = useState(true);

  useEffect(() => {
    const t = setInterval(() => setActivePhase(p => p < PHASES.length ? p+1 : p), 2200);
    return () => clearInterval(t);
  }, []);

  const codeLines = OBFUSCATED_CODE.split('\n');

  return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', overflow:'hidden' }}>
      {/* file pill strip */}
      <FileStrip status="running" lang={lang} lt={lth} />

      {/* phase bar */}
      <div style={{ height:36, background: C.bg2, borderBottom:`1px solid ${C.border}`,
        display:'flex', alignItems:'center', gap:0, padding:'0 14px', flexShrink:0, overflow:'hidden' }}>
        {PHASES.map((ph, i) => {
          const done   = i < activePhase;
          const active = i === activePhase;
          return (
            <React.Fragment key={ph.id}>
              <div style={{ display:'flex', alignItems:'center', gap:5 }}>
                <div style={{ width:18, height:18, borderRadius:2, flexShrink:0,
                  display:'flex', alignItems:'center', justifyContent:'center', fontSize:9.5,
                  fontFamily: C.mono, fontWeight:600,
                  background: done ? C.tealDim : active ? lth.accentDim : C.bg3,
                  border: `1px solid ${done ? C.teal : active ? lth.accent : C.border2}`,
                  color: done ? C.teal : active ? lth.accentText : C.textMuted }}>
                  {done
                    ? <Ico d="M3 8l4 4 6-6" size={10} col={C.teal} />
                    : active
                      ? <div style={{ width:8, height:8, borderRadius:'50%',
                          border:`1.5px solid ${lth.accent}`, borderTopColor:'transparent',
                          animation:'spin .7s linear infinite' }} />
                      : ph.short}
                </div>
                <span style={{ fontSize:11.5, fontFamily: C.mono,
                  color: done ? C.green : active ? lth.accentText : C.textMuted }}>
                  {ph.label}
                </span>
              </div>
              {i < PHASES.length-1 && (
                <div style={{ width:28, height:1, background: done ? C.teal : C.border,
                  margin:'0 8px', flexShrink:0 }} />
