            </React.Fragment>
          );
        })}
        <div style={{ flex:1 }} />
        <span style={{ fontSize:11, fontFamily: C.mono, color: C.textMuted }}>
          eta ~6s
        </span>
      </div>

      {/* body */}
      <div style={{ flex:1, display:'flex', overflow:'hidden' }}>

        {/* left: layer cards */}
        <div style={{ width:220, borderRight:`1px solid ${C.border}`, background: C.bg1,
          overflowY:'auto', display:'flex', flexDirection:'column', flexShrink:0 }}>
