// ─── IOC-highlighted code row ────────────────────────────────────────────────
function IocRow({ isIoc, isAdd, isDel, ln, line, iocLabel }) {
  const [hovered, setHovered] = React.useState(false);

  const baseBg = isIoc
    ? hovered ? 'rgba(212,95,95,.18)' : 'rgba(212,95,95,.07)'
    : isAdd ? 'rgba(76,175,110,.08)'
    : isDel ? 'rgba(212,95,95,.08)'
    : 'transparent';

  return (
    <tr
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ background: baseBg, cursor: isIoc ? 'default' : undefined,
        borderLeft: isIoc ? `2px solid ${hovered ? 'rgba(212,95,95,.7)' : 'rgba(212,95,95,.3)'}` : '2px solid transparent',
        transition: 'background .1s, border-color .1s' }}>
      <td style={{ width:14, verticalAlign:'top', paddingTop:3, paddingLeft:6, position:'relative' }}>
