        {ln}
      </td>
      <td style={{ paddingRight:0, width:'100%' }}>
        <code style={{
          display:'block', paddingRight:20,
          color: isDel ? '#9a4040' : isAdd ? '#4a8a5a' : colorize(line),
          whiteSpace:'pre-wrap', wordBreak:'break-all' }}>
