            <div style={{ display:'flex', border:`1px solid ${C.border2}`, borderRadius:3, overflow:'hidden' }}>
              {[1,2,3].map(n => (
                <button key={n} onClick={()=>setScrubber(n)}
                  style={{ padding:'3px 11px', fontSize:11, fontFamily: C.mono, cursor:'pointer',
                    background: scrubber===n ? lth.accentDim : 'transparent',
                    color: scrubber===n ? lth.accentText : C.textDim,
                    border:'none',
                    borderRight: n<3 ? `1px solid ${C.border2}` : 'none' }}>
                  L{n}
                </button>
              ))}
            </div>
            <span style={{ fontSize:10.5, fontFamily: C.mono, color: C.textMuted }}>
              {scrubber===1 ? 'obfuscated' : scrubber===2 ? 'XOR decoded' : 'cleaned'}
            </span>
            <span style={{ marginLeft:'auto', fontSize:10.5, fontFamily: C.mono, color: C.textMuted,
              display:'flex', alignItems:'center', gap:10 }}>
              <span>{['51 234 B','42 158 B','28 154 B'][scrubber-1]}</span>
              <span style={{ color: C.border2 }}>·</span>
              <span>{['1 247','998','623'][scrubber-1]} lines</span>
            </span>
          </div>

          <CodeViewer lines={OBFUSCATED_CODE.split('\n')} />
        </div>
      </div>

      <LogStrip running lt={lth} />
    </div>
  );
}

// ─── IOC-highlighted code row ────────────────────────────────────────────────
function IocRow({ isIoc, isAdd, isDel, ln, line, iocLabel }) {
  const [hovered, setHovered] = React.useState(false);

  const baseBg = isIoc
    ? hovered ? 'rgba(212,95,95,.18)' : 'rgba(212,95,95,.07)'
    : isAdd ? 'rgba(76,175,110,.08)'
    : isDel ? 'rgba(212,95,95,.08)'
    : 'transparent';

  return (
    <tr
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ background: baseBg, cursor: isIoc ? 'default' : undefined,
        borderLeft: isIoc ? `2px solid ${hovered ? 'rgba(212,95,95,.7)' : 'rgba(212,95,95,.3)'}` : '2px solid transparent',
        transition: 'background .1s, border-color .1s' }}>
      <td style={{ width:14, verticalAlign:'top', paddingTop:3, paddingLeft:6, position:'relative' }}>
      </td>
      <td style={{ width:38, textAlign:'right', paddingRight:14,
        color: isIoc ? (hovered ? '#9a5050' : '#606060') : '#606060',
        userSelect:'none', fontSize:11, verticalAlign:'top', paddingLeft:0 }}>
        {ln}
      </td>
      <td style={{ paddingRight:0, width:'100%' }}>
        <code style={{
          display:'block', paddingRight:20,
          color: isDel ? '#9a4040' : isAdd ? '#4a8a5a' : colorize(line),
          whiteSpace:'pre-wrap', wordBreak:'break-all' }}>
          {line || ' '}
        </code>
      </td>
    </tr>
  );
}

