        </span>
      </div>

      {status === 'done' && (
        <>
          <span style={{ color: C.textMuted, fontSize:12 }}>→</span>
          <span style={{ fontFamily: C.mono, fontSize:11, color: C.green }}>12.7 KB</span>
          <span style={{ fontFamily: C.mono, fontSize:10, color: C.textDim,
            background: C.tealDim, border:`1px solid ${C.teal}`,
