          <button onClick={onIocToggle} className="btn-hover"
            style={{ padding:'3px 11px', background: iocOpen ? lth.accentDim : C.bg3,
              border:`1px solid ${iocOpen ? lth.accent : C.border2}`, borderRadius:2,
              fontSize:11.5, color: iocOpen ? lth.accentText : C.textDim,
              cursor:'pointer', fontFamily: C.mono, display:'flex', alignItems:'center', gap:5 }}>
            <span style={{ fontSize:13 }}>{iocOpen ? '✕' : '☰'}</span>
            <span>IOC</span>
          </button>
        </>
      )}

      {status === 'running' && (
        <>
          <div style={{ flex:1 }} />
          <div style={{ display:'flex', alignItems:'center', gap:8 }}>
            <div style={{ width:11, height:11, borderRadius:'50%',
              border:`1.5px solid ${lth.accent}`, borderTopColor:'transparent',
              animation:'spin .7s linear infinite' }} />
            <span style={{ fontSize:11, fontFamily: C.mono, color: lth.accentText }}>
              layer 3/3 · CFG flattening
            </span>
            <span style={{ fontSize:10.5, fontFamily: C.mono, color: C.textMuted }}>
