function LogStrip({ running, done, lt }) {
  const lth = lt || getLangTheme(null);
  const [open, setOpen] = useState(true);
  const [filter, setFilter] = useState('all'); // all | info | debug | ok
  const logRef = useRef(null);

  const levelColor = { DEBUG: '#555555', INFO: '#5a8fd4', OK: '#e0e0e0', WARN: C.orange, ERR: C.red };
  const entryColor = (e) => {
    if (e.level === 'OK')   return '#ffffff';
    if (e.level === 'INFO') return '#7aaee8';
    if (e.level === 'ERR')  return C.red;
    if (e.level === 'WARN') return C.orange;
    if (/\d+%/.test(e.text)) return C.orange;
    if (e.text.startsWith('↳')) return '#8aaecc';
    if (/not applicable/.test(e.text)) return '#353535';
    if (/converged|no changes/.test(e.text)) return '#484848';
    return '#909090';
  };

  const visible = filter === 'all'
    ? LOG_ENTRIES
    : LOG_ENTRIES.filter(e => e.level === filter.toUpperCase());

  useEffect(() => {
    if (open && logRef.current) logRef.current.scrollTop = logRef.current.scrollHeight;
  }, [open]);

  const isLayerHeader = e => e.text.startsWith('──');
  const isDone = e => e.level === 'OK' && e.indent === 0;

  return (
    <div style={{ borderTop:`1px solid ${C.border}`, background: C.bg1, flexShrink:0 }}>
      {/* header bar */}
      <div style={{ display:'flex', alignItems:'center', borderBottom: open ? `1px solid ${C.border}` : 'none' }}>
        <button onClick={()=>setOpen(!open)} className="btn-hover"
          style={{ background:'none', border:'none', cursor:'pointer',
            padding:'5px 10px 5px 12px', display:'flex', alignItems:'center', gap:7 }}>
          <Ico d={open ? "M4 10l4-4 4 4" : "M4 6l4 4 4-4"} col={C.textMuted} />
          <span style={{ fontFamily: C.mono, fontSize:11, color: C.textMuted }}>log</span>
        </button>
        <span style={{ fontFamily: C.mono, fontSize:10, padding:'0 5px', borderRadius:2,
          background: C.bg3, border:`1px solid ${C.border}`, color: C.textMuted }}>
          {LOG_ENTRIES.length} lines
        </span>
        {running && (
          <span style={{ fontFamily: C.mono, fontSize:10, color: lth.accentText, marginLeft:8,
            animation:'pulse 1.2s ease-in-out infinite' }}>● running</span>
        )}
        {done && (
          <span style={{ fontFamily: C.mono, fontSize:10, color: C.teal, marginLeft:8 }}>
            ✓ done · 16.1s
          </span>
        )}
        {open && (
          <div style={{ display:'flex', gap:2, marginLeft:'auto', paddingRight:10 }}>
            {['all','info','ok','debug'].map(f => (
              <button key={f} onClick={()=>setFilter(f)} className="btn-hover"
                style={{ padding:'2px 7px', borderRadius:2, fontSize:10, fontFamily: C.mono,
                  background: filter===f ? C.bg4 : 'none',
                  border: `1px solid ${filter===f ? C.border2 : 'transparent'}`,
                  color: filter===f
                    ? (f==='ok' ? C.teal : f==='info' ? '#6b7a9b' : f==='debug' ? '#4a5a4a' : C.textDim)
                    : C.textMuted,
                  cursor:'pointer' }}>
                {f}
              </button>
            ))}
          </div>
        )}
      </div>

      {open && (
        <div ref={logRef}
          style={{ background:'#080808', maxHeight:180, overflowY:'auto',
            fontFamily: C.mono, fontSize:11, lineHeight:1.6 }}>
          {visible.map((e, i) => {
            const col = levelColor[e.level] || '#484843';
            const header = isLayerHeader(e);
            const okDone = isDone(e);
            return (
              <div key={i} style={{
                display:'flex', gap:0, padding: header ? '4px 0 2px' : '0',
                background: okDone ? 'rgba(78,201,176,.05)' : header ? 'rgba(255,255,255,.02)' : 'transparent',
                borderTop: header ? `1px solid ${C.border}` : 'none',
              }}>
                {/* timestamp */}
                <span style={{ color:'#303030', paddingLeft:12, paddingRight:8,
                  userSelect:'none', flexShrink:0, fontSize:10 }}>
                  {e.t}
                </span>
                {/* level badge */}
                <span style={{ width:38, flexShrink:0, textAlign:'right', paddingRight:8,
                  color: col, fontSize:10, fontWeight: e.level==='OK' ? 600 : 400 }}>
                  {e.level}
                </span>
                {/* indent + text */}
                <span style={{
                  color: header ? '#3a3a4a' : entryColor(e),
                  paddingLeft: e.indent * 12,
                  fontWeight: header || okDone ? 500 : 400,
                  flex:1, paddingRight:14 }}>
                  {e.text}
                </span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

