          {view === 'results'   && <ResultsState iocOpen={iocOpen} setIocOpen={v=>setTweak('iocOpen',v)} lang={lang} lt={lt} />}
        </div>
      </div>
      <Footer view={view} lt={lt} />

      <TweaksPanel>
        <TweakSection label="View">
          <TweakRadio id="view" label="Screen" value={view}
            options={[
              {value:'empty',     label:'Upload'},
              {value:'analyzing', label:'Analyzing'},
              {value:'results',   label:'Results'},
            ]}
            onChange={v=>setTweak('view',v)} />
        </TweakSection>
        <TweakSection label="Language">
          <TweakRadio id="lang" label="File type" value={lang}
            options={[
              {value:'js',  label:'JS'},
              {value:'py',  label:'Python'},
            ]}
            onChange={v=>setTweak('lang',v)} />
        </TweakSection>
        <TweakSection label="Layout">
          <TweakToggle id="sidebarCollapsed" label="Collapse sidebar"
            value={sidebarCollapsed} onChange={v=>setTweak('sidebarCollapsed',v)} />
          {view==='results' && (
            <TweakToggle id="iocOpen" label="IOC panel"
              value={iocOpen} onChange={v=>setTweak('iocOpen',v)} />
          )}
        </TweakSection>
      </TweaksPanel>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<App />);

IocRow:
function IocRow({ isIoc, isAdd, isDel, ln, line, iocLabel }) {
  const [hovered, setHovered] = React.useState(false);

  const baseBg = isIoc
    ? hovered ? 'rgba(212,95,95,.18)' : 'rgba(212,95,95,.07)'
    : isAdd ? 'rgba(76,175,110,.08)'
    : isDel ? 'rgba(212,95,95,.08)'
    : 'transparent';

  return (
    <tr
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ background: baseBg, cursor: isIoc ? 'default' : undefined,
        borderLeft: isIoc ? `2px solid ${hovered ? 'rgba(212,95,95,.7)' : 'rgba(212,95,95,.3)'}` : '2px solid transparent',
        transition: 'background .1s, border-color .1s' }}>
      <td style={{ width:14, verticalAlign:'top', paddingTop:3, paddingLeft:6, position:'relative' }}>
      </td>
      <td style={{ width:38, textAlign:'right', paddingRight:14,
        color: isIoc ? (hovered ? '#9a5050' : '#606060') : '#606060',
        userSelect:'none', fontSize:11, verticalAlign:'top', paddingLeft:0 }}>
        {ln}
      </td>
      <td style={{ paddingRight:0, width:'100%' }}>
        <code style={{
          display:'block', paddingRight:20,
          color: isDel ? '#9a4040' : isAdd ? '#4a8a5a' : colorize(line),
          whiteSpace:'pre-wrap', wordBreak:'break-all' }}>
          {line || ' '}
        </code>
      </td>
    </tr>
  );
}

