                style={{ padding:'7px 14px', background: tab===t.id ? C.bg : 'none',
                  border:'none', borderBottom: tab===t.id ? `2px solid ${lth.accent}` : '2px solid transparent',
                  cursor:'pointer', fontSize:11.5, fontFamily: C.mono,
